from dataclasses import dataclass
from enum import Enum


class StopReason(Enum):
    SUCCESS = "success"
    BUDGET = "budget"
    ERROR = "error"
    ESCALATE = "escalate"


@dataclass
class BudgetGuard:
    max_steps: int
    max_wall_seconds: float
    _steps: int = 0
    _start: float = 0.0

    def start(self) -> None:
        import time
        self._start = time.monotonic()

    def tick(self) -> None:
        self._steps += 1

    def over_step_budget(self) -> bool:
        return self._steps >= self.max_steps

    def over_time_budget(self) -> bool:
        import time
        return (time.monotonic() - self._start) >= self.max_wall_seconds

    def exceeded(self) -> bool:
        return self.over_step_budget() or self.over_time_budget()

    def reason(self) -> str:
        if self.over_step_budget():
            return f"step budget ({self._steps}/{self.max_steps})"
        return f"time budget ({self.max_wall_seconds}s)"


# Usage in the agent loop:
guard = BudgetGuard(max_steps=15, max_wall_seconds=120.0)
guard.start()

while True:
    # ... Think / Act / Observe ...
    guard.tick()
    if guard.exceeded():
        return {"stop": StopReason.BUDGET, "reason": guard.reason()}

# Stop on unrecoverable error categories — don't waste budget retrying them.

UNRECOVERABLE_ERROR_TYPES = {
    "authentication_error",   # wrong API key — no retry will help
    "permission_denied",      # caller lacks access to the resource
    "not_found",              # resource deleted or never existed
}

def should_stop_on_error(error_type: str, consecutive_errors: int) -> bool:
    # Immediate stop for fatal error classes
    if error_type in UNRECOVERABLE_ERROR_TYPES:
        return True
    # Escalate after too many consecutive soft errors
    return consecutive_errors >= 3


# In the tool dispatch loop:
consecutive_errors = 0
for block in tool_calls:
    try:
        result = registry.dispatch(block.name, block.input)
        consecutive_errors = 0  # reset on success
        tool_results.append(make_result(block, result))
    except ToolError as e:
        consecutive_errors += 1
        tool_results.append(make_error_result(block, e))
        if should_stop_on_error(e.error_type, consecutive_errors):
            return {"stop": "error", "reason": str(e)}

from typing import Callable


def loop_with_goal(
    client,
    task: str,
    system: str,
    tools: list[dict],
    registry,
    is_done: Callable[[list[dict]], bool],
    max_steps: int = 20,
) -> dict:
    """
    Loop with a caller-supplied goal predicate.
    Stops as soon as is_done(messages) returns True, even mid-loop.
    """
    messages = [{"role": "user", "content": task}]
    for step in range(max_steps):
        # Goal check before each step — avoids an unnecessary model call
        if is_done(messages):
            return {"stop": "goal", "steps": step, "messages": messages}

        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            system=system,
            tools=tools,
            messages=messages,
        )
        tool_calls = [b for b in response.content if b.type == "tool_use"]

        if response.stop_reason == "end_turn" and not tool_calls:
            # Natural stop — run goal check one final time
            if is_done(messages + [{"role": "assistant", "content": response.content}]):
                return {"stop": "success", "steps": step + 1}
            # Goal not met despite end_turn — treat as budget exhaustion
            return {"stop": "budget", "steps": step + 1, "note": "end_turn but goal unmet"}

        messages.append({"role": "assistant", "content": response.content})
        tool_results = [
            {"type": "tool_result", "tool_use_id": b.id,
             "content": str(registry.dispatch(b.name, b.input).output)}
            for b in tool_calls
        ]
        messages.append({"role": "user", "content": tool_results})

    return {"stop": "budget", "steps": max_steps}


