import signal
import threading


class GracefulShutdown:
    """
    Cooperative cancellation for long-running agent loops.
    Call request_stop() from a signal handler or timeout thread;
    the loop polls should_stop() and exits cleanly at the next step boundary.
    """

    def __init__(self) -> None:
        self._stop = threading.Event()
        self._reason = ""

    def request_stop(self, reason: str = "shutdown requested") -> None:
        self._reason = reason
        self._stop.set()

    def should_stop(self) -> bool:
        return self._stop.is_set()

    @property
    def reason(self) -> str:
        return self._reason


# Wire SIGTERM to graceful shutdown
shutdown = GracefulShutdown()
signal.signal(signal.SIGTERM, lambda *_: shutdown.request_stop("SIGTERM"))

# In the agent loop, check at the top of every iteration:
while True:
    if shutdown.should_stop():
        return {"stop": "shutdown", "reason": shutdown.reason}
    # ... Think / Act / Observe ...

def is_idle(messages: list[dict], window: int = 4) -> bool:
    """
    Detect when the agent is making no progress: the last `window` tool results
    are all identical (same tool, same output). An idle agent is stuck in a loop
    and should stop rather than burning the full step budget.
    """
    if len(messages) < window * 2:
        return False

    # Collect tool results from the last N user turns
    results = []
    for m in reversed(messages):
        if m["role"] == "user" and isinstance(m["content"], list):
            for block in m["content"]:
                if block.get("type") == "tool_result":
                    results.append(block.get("content", ""))
            if len(results) >= window:
                break

    if len(results) < window:
        return False

    # All results identical → agent is stuck
    return len(set(results[-window:])) == 1


# In the loop, after recording tool results:
if is_idle(messages):
    return {
        "stop": "idle",
        "reason": "agent repeated the same tool call with identical results",
        "steps": state.step,
    }
